13	    var width;
14	
15	    if (typeof width_or_matrix !== 'object') {
16	        width = width_or_matrix;
17	    } else {
18	        height = width_or_matrix.length;
19	        width = width_or_matrix[0].length;
20	        matrix = width_or_matrix;
21	    }
22	
23	    /**
