28	    /**
29	     * The number of rows of the grid.
30	     * @type number
31	     */
32	    this.height = height;
33	
34	    /**
35	     * A 2D array of nodes.
36	     */
37	    this.nodes = this._buildNodes(width, height, matrix);
38	}
