40	/**
41	 * Build and return the nodes.
42	 * @private
43	 * @param {number} width
44	 * @param {number} height
45	 * @param {Array<Array<number|boolean>>} [matrix] - A 0-1 matrix representing
46	 *     the walkable status of the nodes.
47	 * @see Grid
48	 */
49	Grid.prototype._buildNodes = function(width, height, matrix) {
50	    var i, j,
51	        nodes = new Array(height);
52	
53	    for (i = 0; i < height; ++i) {
54	        nodes[i] = new Array(width);
55	        for (j = 0; j < width; ++j) {
56	            nodes[i][j] = new Node(j, i);
57	        }
58	    }
59	
60	
61	    if (matrix === undefined) {
62	        return nodes;
63	    }
64	
65	    if (matrix.length !== height || matrix[0].length !== width) {
66	        throw new Error('Matrix size does not fit');
67	    }
68	
69	    for (i = 0; i < height; ++i) {
70	        for (j = 0; j < width; ++j) {
71	            if (matrix[i][j]) {
72	                // 0, false, null will be walkable
73	                // while others will be un-walkable
74	                nodes[i][j].walkable = false;
75	            }
76	        }
77	    }
78	
79	    return nodes;
80	};
81	
82	
83	Grid.prototype.getNodeAt = function(x, y) {
84	    return this.nodes[y][x];
85	};
86	
87	
88	/**
89	 * Determine whether the node at the given position is walkable.
90	 * (Also returns false if the position is outside the grid.)
91	 * @param {number} x - The x coordinate of the node.
92	 * @param {number} y - The y coordinate of the node.
93	 * @return {boolean} - The walkability of the node.
94	 */
95	Grid.prototype.isWalkableAt = function(x, y) {
96	    return this.isInside(x, y) && this.nodes[y][x].walkable;
97	};
98	
99	
100	/**
101	 * Determine whether the position is inside the grid.
102	 * XXX: `grid.isInside(x, y)` is wierd to read.
103	 * It should be `(x, y) is inside grid`, but I failed to find a better
104	 * name for this method.
105	 * @param {number} x
106	 * @param {number} y
107	 * @return {boolean}
108	 */
109	Grid.prototype.isInside = function(x, y) {
110	    return (x >= 0 && x < this.width) && (y >= 0 && y < this.height);
111	};
112	
113	
114	/**
115	 * Set whether the node on the given position is walkable.
116	 * NOTE: throws exception if the coordinate is not inside the grid.
117	 * @param {number} x - The x coordinate of the node.
118	 * @param {number} y - The y coordinate of the node.
119	 * @param {boolean} walkable - Whether the position is walkable.
120	 */
121	Grid.prototype.setWalkableAt = function(x, y, walkable) {
122	    this.nodes[y][x].walkable = walkable;
123	};
124	
125	
126	/**
127	 * Get the neighbors of the given node.
128	 *
129	 *     offsets      diagonalOffsets:
130	 *  +---+---+---+    +---+---+---+
131	 *  |   | 0 |   |    | 0 |   | 1 |
132	 *  +---+---+---+    +---+---+---+
133	 *  | 3 |   | 1 |    |   |   |   |
134	 *  +---+---+---+    +---+---+---+
135	 *  |   | 2 |   |    | 3 |   | 2 |
136	 *  +---+---+---+    +---+---+---+
137	 *
138	 *  When allowDiagonal is true, if offsets[i] is valid, then
139	 *  diagonalOffsets[i] and
140	 *  diagonalOffsets[(i + 1) % 4] is valid.
141	 * @param {Node} node
142	 * @param {DiagonalMovement} diagonalMovement
143	 */
144	Grid.prototype.getNeighbors = function(node, diagonalMovement) {
145	    var x = node.x,
146	        y = node.y,
147	        neighbors = [],
148	        s0 = false, d0 = false,
149	        s1 = false, d1 = false,
150	        s2 = false, d2 = false,
151	        s3 = false, d3 = false,
152	        nodes = this.nodes;
153	
154	    // ↑
155	    if (this.isWalkableAt(x, y - 1)) {
156	        neighbors.push(nodes[y - 1][x]);
157	        s0 = true;
158	    }
159	    // →
160	    if (this.isWalkableAt(x + 1, y)) {
161	        neighbors.push(nodes[y][x + 1]);
162	        s1 = true;
163	    }
164	    // ↓
165	    if (this.isWalkableAt(x, y + 1)) {
166	        neighbors.push(nodes[y + 1][x]);
167	        s2 = true;
168	    }
169	    // ←
170	    if (this.isWalkableAt(x - 1, y)) {
171	        neighbors.push(nodes[y][x - 1]);
172	        s3 = true;
173	    }
174	
175	    if (diagonalMovement === DiagonalMovement.Never) {
176	        return neighbors;
177	    }
178	
179	    if (diagonalMovement === DiagonalMovement.OnlyWhenNoObstacles) {
180	        d0 = s3 && s0;
181	        d1 = s0 && s1;
182	        d2 = s1 && s2;
183	        d3 = s2 && s3;
184	    } else if (diagonalMovement === DiagonalMovement.IfAtMostOneObstacle) {
185	        d0 = s3 || s0;
186	        d1 = s0 || s1;
187	        d2 = s1 || s2;
188	        d3 = s2 || s3;
189	    } else if (diagonalMovement === DiagonalMovement.Always) {
190	        d0 = true;
191	        d1 = true;
192	        d2 = true;
193	        d3 = true;
194	    } else {
195	        throw new Error('Incorrect value of diagonalMovement');
196	    }
197	
198	    // ↖
199	    if (d0 && this.isWalkableAt(x - 1, y - 1)) {
200	        neighbors.push(nodes[y - 1][x - 1]);
201	    }
202	    // ↗
203	    if (d1 && this.isWalkableAt(x + 1, y - 1)) {
204	        neighbors.push(nodes[y - 1][x + 1]);
205	    }
206	    // ↘
207	    if (d2 && this.isWalkableAt(x + 1, y + 1)) {
208	        neighbors.push(nodes[y + 1][x + 1]);
209	    }
210	    // ↙
211	    if (d3 && this.isWalkableAt(x - 1, y + 1)) {
212	        neighbors.push(nodes[y + 1][x - 1]);
213	    }
214	
215	    return neighbors;
216	};
217	
218	
219	/**
220	 * Get a clone of this grid.
221	 * @return {Grid} Cloned grid.
222	 */
223	Grid.prototype.clone = function() {
224	    var i, j,
225	
