    '## Map 1: Sparse',
    '',
    '- **Start:** (0, 0)',
    '- **End:** (14, 14)',
    '- **Path length:** ' + r1.pathLength + ' nodes',
    '- **Nodes explored:** ' + r1.nodesExplored,
    '- **Avg execution time:** ' + r1.avgMs + ' ms',
    '',
    '---',
    '',
    '## Map 2: Spiral',
    '',
    '- **Start:** (0, 0)',
    '- **End:** (7, 7) — center',
    '- **Path length:** ' + r2.pathLength + ' nodes',
    '- **Nodes explored:** ' + r2.nodesExplored,
    '- **Avg execution time:** ' + r2.avgMs + ' ms',
    '',
    '---',
    '',
    '_Generated by racer-astar benchmark_',
].join('\n');

var outPath = path.join(__dirname, 'results.md');
fs.writeFileSync(outPath, md);
